		return m.viewSelectedPlan()

	case "rename_plan":
		planFile := m.nav.GetSelectedPlanFile()
		if planFile == "" {
			return m, nil
		}
		currentName := taskstate.DisplayName(planFile)
		m.state = stateRenameTask
		tio := overlay.NewTextInputOverlay("rename task", currentName)
		tio.SetSize(60, 3)
		m.overlays.Show(tio)
